// Extract market data from webhook payload
const marketData = $input.first().json.body || $input.first().json;

// Build keywords from category and question
const words = (marketData.question || '').split(' ').filter(w => w.length > 3);
const keywords = [
  marketData.category,
  ...words.slice(0, 10)
];

// Bengali and international news sources
const bengaliSources = [
  'prothomalo.com',
  'bdnews24.com',
  'banglatribune.com',
  'thedailystar.net',
  'somoynews.tv',
  'dailybangladeshtimes.com'
];

const internationalSources = [
  'bbc.com',
  'reuters.com',
  'apnews.com'
];

return {
  json: {
    market_id: marketData.market_id,
    question: marketData.question,
    category: marketData.category,
    keywords,
    sources: [...bengaliSources, ...internationalSources],
    trigger_source: marketData.trigger_source || 'manual'
  }
};

// Combine all search results
const googleBD = $input.byIndex[0].json.items || [];
const googleIntl = $input.byIndex[1].json.items || [];
const newsBengali = $input.byIndex[2].json.articles || [];

// Deduplicate and format sources
const seenUrls = new Set();
const sources = [];

// Process Bengali news first (priority)
for (const item of googleBD) {
  if (!seenUrls.has(item.link)) {
    seenUrls.add(item.link);
    sources.push({
      url: item.link,
      title: item.title,
      snippet: item.snippet,
      source: 'google_bd',
      language: 'bn'
    });
  }
}

for (const item of newsBengali) {
  if (!seenUrls.has(item.url)) {
    seenUrls.add(item.url);
    sources.push({
      url: item.url,
      title: item.title,
      snippet: item.description,
      source: 'newsapi',
      language: 'bn'
    });
  }
}

for (const item of googleIntl) {
  if (!seenUrls.has(item.link)) {
    seenUrls.add(item.link);
    sources.push({
      url: item.link,
      title: item.title,
      snippet: item.snippet,
      source: 'google_intl',
      language: 'en'
    });
  }
}

return {
  json: {
    ...$input.first().json,
    sources: sources.slice(0, 10)
  }
};

// Parse Gemini response
const geminiResponse = $input.first().json.response;
let analysis;

try {
  // Try to find and parse JSON
  const jsonMatch = geminiResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found');
  }
} catch (e) {
  // Fallback parsing
  const lowerResp = geminiResponse.toLowerCase();
  const outcome = lowerResp.includes('"yes"') ? 'YES' :
                  lowerResp.includes('"no"') ? 'NO' : 'UNCERTAIN';

  const confidenceMatch = geminiResponse.match(/(\d+)\s*%/);
  const confidence = confidenceMatch ? parseInt(confidenceMatch[1]) : 50;

  analysis = {
    outcome,
    confidence_score: confidence,
    reasoning: geminiResponse.substring(0, 500),
    relevant_sources: []
  };
}

// Ensure valid outcome
if (!['YES', 'NO', 'UNCERTAIN'].includes(analysis.outcome)) {
  analysis.outcome = 'UNCERTAIN';
}

// Ensure confidence is 0-100
analysis.confidence_score = Math.max(0, Math.min(100, analysis.confidence_score || 50));

return {
  json: {
    ...$input.first().json,
    outcome: analysis.outcome,
    confidence_score: analysis.confidence_score,
    reasoning: analysis.reasoning,
    relevant_sources: analysis.relevant_sources || []
  }
};

// Determine if auto-resolve or manual review
const confidence = $input.first().json.confidence_score;
const outcome = $input.first().json.outcome;
const threshold = 90;

const canAutoResolve = confidence >= threshold && outcome !== 'UNCERTAIN';

return {
  json: {
    ...$input.first().json,
    can_auto_resolve: canAutoResolve,
    needs_manual_review: !canAutoResolve,
    resolution_action: canAutoResolve ? 'auto_resolve' : 'manual_review',
    threshold
  }
};

// Format result for Plokymarket
const data = $input.first().json;

const result = {
  success: true,
  market_id: data.market_id,
  question: data.question,
  outcome: data.outcome,
  confidence: data.confidence_score,
  auto_resolved: data.can_auto_resolve,
  needs_manual_review: data.needs_manual_review,
  reasoning: data.reasoning,
  sources_count: data.sources?.length || 0,
  timestamp: new Date().toISOString()
};

return { json: result };
